import React, { useState, useEffect, useRef } from 'react';
import { slotAPI } from '../services/api';
import io from 'socket.io-client';

const SlotBookingPage = () => {
  const [slots, setSlots] = useState([]);
  const [bookedSlots, setBookedSlots] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [view, setView] = useState('available');
  const [successMessage, setSuccessMessage] = useState('');
  const socketRef = useRef(null);

  useEffect(() => {
    fetchSlots();
  }, []);

  useEffect(() => {
    socketRef.current = io('http://localhost:5000', {
      auth: {
        token: sessionStorage.getItem('token') || localStorage.getItem('token'),
      },
    });

    socketRef.current.on('slot_updated', () => {
      fetchSlots();
    });

    return () => {
      socketRef.current.off('slot_updated');
      socketRef.current.disconnect();
    };
  }, []);

  const fetchSlots = async () => {
    setLoading(true);
    setError('');
    try {
      const [availableRes, bookedRes] = await Promise.all([
        slotAPI.getAvailableSlots(),
        slotAPI.getMySlots(),
      ]);
      setSlots(availableRes.data.slots || []);
      setBookedSlots(bookedRes.data.slots || []);
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to fetch slots');
    } finally {
      setLoading(false);
    }
  };

  const handleBookSlot = async (slotId) => {
    try {
      await slotAPI.bookSlot({ slotId });
      setSuccessMessage('Session booked successfully.');
      setTimeout(() => setSuccessMessage(''), 3000);
      fetchSlots();
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to book slot');
    }
  };

  const handleCancelBooking = async (slotId) => {
    try {
      await slotAPI.cancelBooking(slotId);
      setSuccessMessage('Booking cancelled successfully.');
      setTimeout(() => setSuccessMessage(''), 3000);
      fetchSlots();
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to cancel booking');
    }
  };

  const formatDateTime = (date, time) => {
    try {
      return `${new Date(date).toLocaleDateString()} at ${time}`;
    } catch {
      return `${date} at ${time}`;
    }
  };

  const currentSlots = view === 'available' ? slots : bookedSlots;

  return (
    <div className="container-fluid py-4 min-vh-100">
      <div className="container">
        <div className="portal-page-header">
          <span className="portal-page-kicker">Sessions</span>
          <h1 className="portal-page-title">Slot Booking</h1>
          <p className="portal-page-subtitle">
            Reserve available sessions with staff members and keep track of your confirmed bookings.
          </p>
        </div>

        {error && (
          <div className="alert alert-danger alert-dismissible fade show" role="alert">
            {error}
            <button type="button" className="btn-close" onClick={() => setError('')}></button>
          </div>
        )}

        {successMessage && (
          <div className="alert alert-success alert-dismissible fade show" role="alert">
            {successMessage}
            <button
              type="button"
              className="btn-close"
              onClick={() => setSuccessMessage('')}
            ></button>
          </div>
        )}

        <div className="row g-4 mb-4">
          <div className="col-md-4">
            <div className="card portal-stat-card shadow-sm">
              <div className="card-body">
                <div className="portal-stat-label">Available</div>
                <div className="portal-stat-value">{slots.length}</div>
              </div>
            </div>
          </div>
          <div className="col-md-4">
            <div className="card portal-stat-card shadow-sm">
              <div className="card-body">
                <div className="portal-stat-label">Booked</div>
                <div className="portal-stat-value">{bookedSlots.length}</div>
              </div>
            </div>
          </div>
          <div className="col-md-4">
            <div className="card portal-stat-card shadow-sm">
              <div className="card-body">
                <div className="portal-stat-label">Current View</div>
                <div className="portal-stat-value">{view === 'available' ? 'Open' : 'My Sessions'}</div>
              </div>
            </div>
          </div>
        </div>

        <div className="card portal-section-card shadow-sm mb-4">
          <div className="card-body">
            <div className="portal-chip-group">
              <button
                type="button"
                className={`btn portal-chip ${view === 'available' ? 'btn-primary' : 'btn-outline-primary'}`}
                onClick={() => setView('available')}
              >
                Available Slots
              </button>
              <button
                type="button"
                className={`btn portal-chip ${view === 'booked' ? 'btn-primary' : 'btn-outline-primary'}`}
                onClick={() => setView('booked')}
              >
                My Bookings
              </button>
            </div>
          </div>
        </div>

        {loading ? (
          <div className="text-center py-5">
            <div className="spinner-border text-primary" role="status">
              <span className="visually-hidden">Loading...</span>
            </div>
          </div>
        ) : currentSlots.length === 0 ? (
          <div className="card portal-section-card shadow-sm">
            <div className="portal-empty-state">
              {view === 'available'
                ? 'No available slots at the moment. Please check again later.'
                : 'You have not booked any sessions yet.'}
            </div>
          </div>
        ) : (
          <div className="row g-4">
            {currentSlots.map((slot) => (
              <div key={slot._id} className="col-md-6 col-lg-4">
                <div className="card portal-slot-card shadow-sm">
                  <div className="card-body p-4">
                    <div className="d-flex justify-content-between align-items-start mb-3">
                      <div>
                        <div className="portal-stat-label">
                          {slot.staffId?.subject || 'Session'}
                        </div>
                        <h5 className="fw-bold mb-1">{slot.staffId?.name || 'Staff Member'}</h5>
                      </div>
                      <span className={`badge ${view === 'available' ? 'bg-success' : 'bg-primary'}`}>
                        {view === 'available' ? 'Available' : 'Booked'}
                      </span>
                    </div>
                    <div className="portal-meta-list">
                      <div className="portal-meta-item">
                        <strong>Date & time:</strong> {formatDateTime(slot.date, slot.time)}
                      </div>
                      <div className="portal-meta-item">
                        <strong>Duration:</strong> {slot.duration} minutes
                      </div>
                      <div className="portal-meta-item">
                        <strong>Topic:</strong> {slot.topic || 'To be discussed'}
                      </div>
                    </div>
                  </div>
                  <div className="card-footer bg-transparent border-0 pt-0 px-4 pb-4">
                    {view === 'available' ? (
                      <button className="btn btn-primary w-100" onClick={() => handleBookSlot(slot._id)}>
                        Book Session
                      </button>
                    ) : (
                      <button className="btn btn-danger w-100" onClick={() => handleCancelBooking(slot._id)}>
                        Cancel Booking
                      </button>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default SlotBookingPage;
